external_knowledge:
- 'fueling the daily routine' refers to the average watts (power consumption) used by each zone during normal consumption periods;
- 'power usage check-in' refers to the user's activity of viewing power readings;
- The time frame '2023-10-01 09:00:00' to '2023-10-01 12:00:00' corresponds to the mid-morning period.

sql:
SELECT zone_id, hardware_id, COUNT(*) AS total_readings, AVG(watts) AS average_watts
FROM power_readings
GROUP BY zone_id, hardware_id;

SELECT AVG(watts) AS average_watts
FROM power_reading_history
WHERE zone_id = 0;

SELECT watts
FROM power_readings
WHERE hardware_id = 1 AND watts > 0;

SELECT hardware_name
FROM hardwares
WHERE hardware_id = 1;

SELECT zone_id, time_elapsed, power_j, recorded_at, MAX(watts) AS max_watts
FROM power_reading_history
GROUP BY zone_id, time_elapsed, power_j, recorded_at;

SELECT watts, reading_timestamp
FROM power_readings
WHERE watts = (SELECT MAX(watts) FROM power_readings);

